Password change functionality is a critical security control that attackers frequently target. A common vulnerability is allowing password changes without verifying the current password, which enables account takeover if an attacker gains temporary access to a session.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const pool = require('./db');

const app = express();
app.use(express.json());

// VULNERABLE: No current password verification
app.post('/api/change-password', async (req, res) => {
  const { userId, newPassword } = req.body;

  // Only checks if user is "logged in" via session
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  // VULNERABILITY 1: No current password verification
  // VULNERABILITY 2: Allows changing ANY user's password if userId is provided
  const targetUserId = userId || req.session.userId;

  const hashedPassword = await bcrypt.hash(newPassword, 10);

  await pool.query(
    'UPDATE users SET password = $1 WHERE id = $2',
    [hashedPassword, targetUserId]
  );

  res.json({ message: 'Password changed successfully' });
});
```

**Attack Payload**:
```bash
# Attacker with stolen session cookie changes victim's password
curl -X POST https://target.com/api/change-password \
  -H "Cookie: session=stolen_session_token" \
  -H "Content-Type: application/json" \
  -d '{"newPassword": "attacker_password123"}'

# Or change another user's password via IDOR
curl -X POST https://target.com/api/change-password \
  -H "Cookie: session=valid_attacker_session" \
  -H "Content-Type: application/json" \
  -d '{"userId": 1, "newPassword": "admin_takeover"}'
```

**Why This Is Dangerous**:
- Session hijacking via XSS, network sniffing, or malware allows immediate account takeover
- No re-authentication means stolen sessions have unlimited power
- IDOR vulnerability allows horizontal privilege escalation to any user
- No audit trail of password changes for forensic investigation

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');
const pool = require('./db');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// Rate limiting for password changes
const passwordChangeLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 3, // 3 attempts per window
  message: { error: 'Too many password change attempts' }
});

// SECURE: Requires current password verification
app.post('/api/change-password',
  passwordChangeLimiter,
  [
    body('currentPassword').notEmpty().withMessage('Current password required'),
    body('newPassword')
      .isLength({ min: 12 })
      .withMessage('Password must be at least 12 characters')
      .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/)
      .withMessage('Password must include uppercase, lowercase, number, and special character'),
    body('confirmPassword').custom((value, { req }) => {
      if (value !== req.body.newPassword) {
        throw new Error('Passwords do not match');
      }
      return true;
    })
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // SECURITY: Only allow changing own password from session
    if (!req.session.userId) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const { currentPassword, newPassword } = req.body;
    const userId = req.session.userId; // NEVER from request body

    try {
      // Fetch current password hash
      const result = await pool.query(
        'SELECT password FROM users WHERE id = $1',
        [userId]
      );

      if (result.rows.length === 0) {
        return res.status(404).json({ error: 'User not found' });
      }

      // CRITICAL: Verify current password
      const validPassword = await bcrypt.compare(
        currentPassword,
        result.rows[0].password
      );

      if (!validPassword) {
        // Log failed attempt
        console.log(`Failed password change attempt for user ${userId}`);
        return res.status(401).json({ error: 'Current password incorrect' });
      }

      // Hash and update new password
      const hashedPassword = await bcrypt.hash(newPassword, 12);

      await pool.query(
        'UPDATE users SET password = $1, password_changed_at = NOW() WHERE id = $2',
        [hashedPassword, userId]
      );

      // Invalidate all other sessions
      await pool.query(
        'DELETE FROM sessions WHERE user_id = $1 AND session_id != $2',
        [userId, req.session.id]
      );

      // Log successful change
      console.log(`Password changed successfully for user ${userId}`);

      res.json({ message: 'Password changed successfully' });
    } catch (error) {
      console.error('Password change error:', error);
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);
```

**Key Security Controls**:
- **Current password verification**: Re-authenticates user before allowing password change, preventing session hijacking attacks
- **No user ID from request body**: Only uses session user ID, preventing IDOR attacks
- **Rate limiting**: Prevents brute force attempts against current password
- **Session invalidation**: Logs out all other sessions after password change
- **Strong password policy**: Enforces complexity requirements

Password reset flows are even more critical because they bypass normal authentication entirely. Poor implementations lead to account takeovers via predictable tokens, token leakage, or lack of expiration.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');
const pool = require('./db');
const rateLimit = require('express-rate-limit');
const nodemailer = require('nodemailer');

const app = express();
app.use(express.json());

// Configuration
const TOKEN_EXPIRY_MINUTES = 15;
const MAX_RESET_ATTEMPTS = 3;

// Strict rate limiting for reset requests
const resetRequestLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 3,
  keyGenerator: (req) => req.body.email || req.ip,
  handler: (req, res) => {
    console.warn(`Rate limit exceeded for reset: ${req.body.email || req.ip}`);
    // Return same response to prevent enumeration
    res.json({ message: 'If the email exists, a reset link has been sent' });
  }
});

const resetSubmitLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  message: { error: 'Too many attempts. Please request a new reset link.' }
});

// STEP 1: Request password reset
app.post('/api/forgot-password',
  resetRequestLimiter,
  body('email').isEmail().normalizeEmail(),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      // Return generic response to prevent enumeration
      return res.json({ message: 'If the email exists, a reset link has been sent' });
    }

    const { email } = req.body;

    try {
      // Check if user exists (timing-safe)
      const userResult = await pool.query(
        'SELECT id, email FROM users WHERE email = $1',
        [email]
      );

      // SECURITY: Always return same response regardless of user existence
      const genericResponse = { message: 'If the email exists, a reset link has been sent' };

      if (userResult.rows.length === 0) {
        // Simulate processing time to prevent timing attacks
        await new Promise(resolve => setTimeout(resolve, 100 + Math.random() * 100));
        return res.json(genericResponse);
      }

      const user = userResult.rows[0];

      // Generate cryptographically secure token
      const resetToken = crypto.randomBytes(32).toString('hex');
      const tokenHash = crypto
        .createHash('sha256')
        .update(resetToken)
        .digest('hex');

      // Store hashed token with expiry
      const expiresAt = new Date(Date.now() + TOKEN_EXPIRY_MINUTES * 60 * 1000);

      await pool.query(
        `INSERT INTO password_resets (user_id, token_hash, expires_at, attempts, created_at)
         VALUES ($1, $2, $3, 0, NOW())
         ON CONFLICT (user_id) DO UPDATE 
         SET token_hash = $2, expires_at = $3, attempts = 0, created_at = NOW()`,
        [user.id, tokenHash, expiresAt]
      );

      // Send email with unhashed token
      const resetUrl = `https://yourapp.com/reset-password?token=${resetToken}&email=${encodeURIComponent(email)}`;

      await sendResetEmail(email, resetUrl);

      // Audit log
      console.log(`Password reset requested for user ${user.id} from ${req.ip}`);

      res.json(genericResponse);
    } catch (error) {
      console.error('Password reset request error:', error);
      res.json({ message: 'If the email exists, a reset link has been sent' });
    }
  }
);

// STEP 2: Validate token and reset password
app.post('/api/reset-password',
  resetSubmitLimiter,
  [
    body('token').isLength({ min: 64, max: 64 }).isHexadecimal(),
    body('email').isEmail().normalizeEmail(),
    body('newPassword')
      .isLength({ min: 12 })
      .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/),
    body('confirmPassword').custom((value, { req }) => {
      if (value !== req.body.newPassword) {
        throw new Error('Passwords do not match');
      }
      return true;
    })
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid request' });
    }

    const { token, email, newPassword } = req.body;

    try {
      // Hash the provided token for comparison
      const tokenHash = crypto
        .createHash('sha256')
        .update(token)
        .digest('hex');

      // Find valid reset record
      const resetResult = await pool.query(
        `SELECT pr.id, pr.user_id, pr.attempts, u.email
         FROM password_resets pr
         JOIN users u ON u.id = pr.user_id
         WHERE pr.token_hash = $1 
         AND u.email = $2
         AND pr.expires_at > NOW()
         AND pr.attempts < $3`,
        [tokenHash, email, MAX_RESET_ATTEMPTS]
      );

      if (resetResult.rows.length === 0) {
        // Increment attempt counter if record exists
        await pool.query(
          `UPDATE password_resets SET attempts = attempts + 1 
           WHERE token_hash = $1`,
          [tokenHash]
        );

        console.warn(`Invalid password reset attempt for ${email} from ${req.ip}`);
        return res.status(400).json({ error: 'Invalid or expired reset link' });
      }

      const resetRecord = resetResult.rows[0];

      // Check if new password was previously used
      const previousPasswords = await pool.query(
        'SELECT password_hash FROM password_history WHERE user_id = $1 ORDER BY created_at DESC LIMIT 5',
        [resetRecord.user_id]
      );

      for (const prev of previousPasswords.rows) {
        if (await bcrypt.compare(newPassword, prev.password_hash)) {
          return res.status(400).json({ error: 'Cannot reuse recent passwords' });
        }
      }

      // Hash new password
      const hashedPassword = await bcrypt.hash(newPassword, 12);

      // Begin transaction
      const client = await pool.connect();
      try {
        await client.query('BEGIN');

        // Update password
        await client.query(
          'UPDATE users SET password = $1, password_changed_at = NOW() WHERE id = $2',
          [hashedPassword, resetRecord.user_id]
        );

        // Store in password history
        await client.query(
          'INSERT INTO password_history (user_id, password_hash, created_at) VALUES ($1, $2, NOW())',
          [resetRecord.user_id, hashedPassword]
        );

        // Delete reset token
        await client.query(
          'DELETE FROM password_resets WHERE user_id = $1',
          [resetRecord.user_id]
        );

        // Invalidate ALL sessions for this user
        await client.query(
          'DELETE FROM sessions WHERE user_id = $1',
          [resetRecord.user_id]
        );

        await client.query('COMMIT');

        // Audit log
        console.log(`Password reset completed for user ${resetRecord.user_id} from ${req.ip}`);

        // Send notification email
        await sendPasswordChangedNotification(email);

        res.json({ message: 'Password has been reset successfully' });
      } catch (error) {
        await client.query('ROLLBACK');
        throw error;
      } finally {
        client.release();
      }
    } catch (error) {
      console.error('Password reset error:', error);
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Helper: Send reset email
async function sendResetEmail(email, resetUrl) {
  const transporter = nodemailer.createTransport({
    host: process.env.SMTP_HOST,
    port: 587,
    secure: false,
    auth: {
      user: process.env.SMTP_USER,
      pass: process.env.SMTP_PASS
    }
  });

  await transporter.sendMail({
    from: '"Security" <security@yourapp.com>',
    to: email,
    subject: 'Password Reset Request',
    html: `
      <p>A password reset was requested for your account.</p>
      <p>Click <a href="${resetUrl}">here</a> to reset your password.</p>
      <p>This link expires in ${TOKEN_EXPIRY_MINUTES} minutes.</p>
      <p>If you didn't request this, please ignore this email and consider enabling 2FA.</p>
    `
  });
}

// Helper: Send password changed notification
async function sendPasswordChangedNotification(email) {
  // Implementation similar to above
  // Alerts user that password was changed
}
```

**Defense in Depth Layers**:

1. **Cryptographically secure tokens**: Uses `crypto.randomBytes(32)` for 256-bit entropy, stored hashed in database
```javascript
const resetToken = crypto.randomBytes(32).toString('hex');
const tokenHash = crypto.createHash('sha256').update(resetToken).digest('hex');
```

2. **Time-limited tokens with attempt limiting**: Tokens expire in 15 minutes with max 3 attempts
```javascript
AND pr.expires_at > NOW()
AND pr.attempts < $3
```

3. **User enumeration prevention**: Same response and timing regardless of user existence
```javascript
await new Promise(resolve => setTimeout(resolve, 100 + Math.random() * 100));
return res.json(genericResponse);
```

**Additional Protections**:
- **Password history check**: Prevents reuse of last 5 passwords
- **Session invalidation**: All sessions terminated on password reset
- **Notification email**: User alerted when password is changed
- **Transaction safety**: Database operations are atomic
- **Rate limiting**: Separate limits for request and submission endpoints
- **Token stored hashed**: Even database compromise doesn't leak valid tokens
- **Email + token validation**: Both must match for successful reset

Your concern is valid - registration endpoints without bot protection are frequently exploited. In 2023, Twitter/X faced massive bot account creation campaigns that compromised platform integrity and cost advertisers over $500M in fraudulent engagement. Let me show you the vulnerability and the fix.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.sql.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;

@RestController
@RequestMapping("/api")
public class RegistrationController {

    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "apppassword";
    private BCryptPasswordEncoder passwordEncoder = new BCryptPasswordEncoder();

    @PostMapping("/register")
    public ResponseEntity<String> registerUser(@RequestBody UserRegistration request) {
        // VULNERABLE: No CAPTCHA verification - bots can register unlimited accounts
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "INSERT INTO users (username, email, password_hash) VALUES (?, ?, ?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, request.getUsername());
            stmt.setString(2, request.getEmail());
            stmt.setString(3, passwordEncoder.encode(request.getPassword()));
            stmt.executeUpdate();
            return ResponseEntity.ok("Registration successful");
        } catch (SQLException e) {
            return ResponseEntity.status(500).body("Registration failed");
        }
    }
}
```

**Attack Script**:
```python
import requests
import string
import random

# Bot creates thousands of fake accounts per minute
for i in range(10000):
    username = ''.join(random.choices(string.ascii_lowercase, k=8))
    payload = {
        "username": f"bot_{username}",
        "email": f"{username}@tempmail.com",
        "password": "Password123!"
    }
    requests.post("https://target.com/api/register", json=payload)
    print(f"Created account {i}")
```

**Why This Is Dangerous**:
- Automated scripts can create thousands of fake accounts per minute
- Fake accounts used for spam, credential stuffing, or influence campaigns
- No way to distinguish human users from bots
- Database fills with garbage data, increasing storage/query costs
- Legitimate users face degraded service quality

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.web.client.RestTemplate;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@RestController
@RequestMapping("/api")
public class SecureRegistrationController {

    private static final Logger logger = LoggerFactory.getLogger(SecureRegistrationController.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "apppassword";
    private static final String RECAPTCHA_VERIFY_URL = "https://www.google.com/recaptcha/api/siteverify";

    @Value("${recaptcha.secret.key}")
    private String recaptchaSecretKey;

    private BCryptPasswordEncoder passwordEncoder = new BCryptPasswordEncoder();
    private RestTemplate restTemplate = new RestTemplate();

    @PostMapping("/register")
    public ResponseEntity<String> registerUser(
            @RequestBody UserRegistration request,
            HttpServletRequest httpRequest) {

        String clientIp = getClientIp(httpRequest);

        // SECURITY: Verify CAPTCHA token before processing
        if (!verifyCaptcha(request.getCaptchaToken(), clientIp)) {
            logger.warn("CAPTCHA verification failed for IP: {}", clientIp);
            return ResponseEntity.status(400).body("CAPTCHA verification failed");
        }

        // Validate input
        if (!isValidRegistration(request)) {
            return ResponseEntity.status(400).body("Invalid registration data");
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "INSERT INTO users (username, email, password_hash) VALUES (?, ?, ?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, request.getUsername());
            stmt.setString(2, request.getEmail());
            stmt.setString(3, passwordEncoder.encode(request.getPassword()));
            stmt.executeUpdate();

            logger.info("New user registered: {} from IP: {}", request.getUsername(), clientIp);
            return ResponseEntity.ok("Registration successful");
        } catch (SQLException e) {
            logger.error("Registration failed for user: {}", request.getUsername(), e);
            return ResponseEntity.status(500).body("Registration failed");
        }
    }

    private boolean verifyCaptcha(String captchaToken, String clientIp) {
        if (captchaToken == null || captchaToken.isEmpty()) {
            return false;
        }

        String verifyUrl = RECAPTCHA_VERIFY_URL + 
            "?secret=" + recaptchaSecretKey + 
            "&response=" + captchaToken + 
            "&remoteip=" + clientIp;

        RecaptchaResponse response = restTemplate.postForObject(
            verifyUrl, null, RecaptchaResponse.class);

        return response != null && response.isSuccess() && response.getScore() >= 0.5;
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private boolean isValidRegistration(UserRegistration request) {
        return request.getUsername() != null && 
               request.getUsername().matches("^[a-zA-Z0-9_]{3,20}$") &&
               request.getEmail() != null &&
               request.getEmail().matches("^[A-Za-z0-9+_.-]+@(.+)$") &&
               request.getPassword() != null &&
               request.getPassword().length() >= 8;
    }
}
```

**Key Security Controls**:
- **CAPTCHA Verification**: reCAPTCHA v3 with score threshold blocks automated bots while allowing legitimate users
- **Server-side validation**: Token verified against Google's servers, not just checked client-side
- **IP logging**: Track registration attempts for abuse detection and forensics
- **Input validation**: Prevent malformed data even if CAPTCHA is bypassed

Excellent question. CAPTCHA-solving services (like 2Captcha, Anti-Captcha) charge $2-3 per 1000 solves, making attacks economically viable for determined attackers. You need defense in depth with multiple layers that increase attack cost beyond profitability.

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.time.*;
import java.util.concurrent.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.web.client.RestTemplate;
import org.springframework.data.redis.core.RedisTemplate;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

@RestController
@RequestMapping("/api")
public class ProductionRegistrationController {

    private static final Logger logger = LoggerFactory.getLogger(ProductionRegistrationController.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Value("${recaptcha.secret.key}")
    private String recaptchaSecretKey;

    @Value("${registration.rate.limit.per.ip:5}")
    private int rateLimitPerIp;

    @Value("${registration.rate.limit.window.minutes:60}")
    private int rateLimitWindowMinutes;

    private final BCryptPasswordEncoder passwordEncoder;
    private final RestTemplate restTemplate;
    private final RedisTemplate<String, String> redisTemplate;
    private final EmailVerificationService emailService;
    private final DeviceFingerprintService fingerprintService;
    private final MeterRegistry meterRegistry;
    private final Counter registrationAttempts;
    private final Counter registrationBlocked;
    private final Counter registrationSuccess;

    public ProductionRegistrationController(
            BCryptPasswordEncoder passwordEncoder,
            RestTemplate restTemplate,
            RedisTemplate<String, String> redisTemplate,
            EmailVerificationService emailService,
            DeviceFingerprintService fingerprintService,
            MeterRegistry meterRegistry) {
        this.passwordEncoder = passwordEncoder;
        this.restTemplate = restTemplate;
        this.redisTemplate = redisTemplate;
        this.emailService = emailService;
        this.fingerprintService = fingerprintService;
        this.meterRegistry = meterRegistry;
        this.registrationAttempts = meterRegistry.counter("registration.attempts");
        this.registrationBlocked = meterRegistry.counter("registration.blocked");
        this.registrationSuccess = meterRegistry.counter("registration.success");
    }

    @PostMapping("/register")
    public ResponseEntity<RegistrationResponse> registerUser(
            @RequestBody UserRegistration request,
            HttpServletRequest httpRequest) {

        registrationAttempts.increment();
        String clientIp = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        String requestId = java.util.UUID.randomUUID().toString();

        // LAYER 1: Rate limiting by IP
        if (isRateLimited(clientIp)) {
            registrationBlocked.increment();
            securityLogger.warn("RATE_LIMITED request_id={} ip={} user_agent={}", 
                requestId, clientIp, userAgent);
            return ResponseEntity.status(429)
                .body(new RegistrationResponse(false, "Too many registration attempts. Try again later."));
        }

        // LAYER 2: Device fingerprint analysis
        DeviceFingerprintResult fingerprint = fingerprintService.analyze(
            request.getDeviceFingerprint(), clientIp, userAgent);

        if (fingerprint.isSuspicious()) {
            registrationBlocked.increment();
            securityLogger.warn("SUSPICIOUS_DEVICE request_id={} ip={} fingerprint_score={}", 
                requestId, clientIp, fingerprint.getScore());
            // Don't reveal detection - just require additional verification
            return ResponseEntity.status(400)
                .body(new RegistrationResponse(false, "Additional verification required."));
        }

        // LAYER 3: CAPTCHA with adaptive scoring
        CaptchaVerificationResult captchaResult = verifyCaptchaWithScoring(
            request.getCaptchaToken(), clientIp, fingerprint.getScore());

        if (!captchaResult.isValid()) {
            registrationBlocked.increment();
            securityLogger.warn("CAPTCHA_FAILED request_id={} ip={} captcha_score={}", 
                requestId, clientIp, captchaResult.getScore());
            return ResponseEntity.status(400)
                .body(new RegistrationResponse(false, "Verification failed. Please try again."));
        }

        // LAYER 4: Email domain validation
        if (!isValidEmailDomain(request.getEmail())) {
            registrationBlocked.increment();
            securityLogger.warn("DISPOSABLE_EMAIL request_id={} ip={} email_domain={}", 
                requestId, clientIp, extractDomain(request.getEmail()));
            return ResponseEntity.status(400)
                .body(new RegistrationResponse(false, "Please use a permanent email address."));
        }

        // LAYER 5: Honeypot field check
        if (request.getWebsite() != null && !request.getWebsite().isEmpty()) {
            registrationBlocked.increment();
            securityLogger.warn("HONEYPOT_TRIGGERED request_id={} ip={}", requestId, clientIp);
            // Return success to confuse bots
            return ResponseEntity.ok(new RegistrationResponse(true, "Registration successful."));
        }

        // LAYER 6: Timing analysis (bots submit too fast)
        if (!isReasonableSubmitTime(request.getFormLoadTimestamp())) {
            registrationBlocked.increment();
            securityLogger.warn("SUSPICIOUS_TIMING request_id={} ip={} submit_time_ms={}", 
                requestId, clientIp, System.currentTimeMillis() - request.getFormLoadTimestamp());
            return ResponseEntity.status(400)
                .body(new RegistrationResponse(false, "Please complete the form again."));
        }

        // All checks passed - create pending registration
        try {
            String verificationToken = createPendingRegistration(request, clientIp);
            emailService.sendVerificationEmail(request.getEmail(), verificationToken);

            registrationSuccess.increment();
            securityLogger.info("REGISTRATION_PENDING request_id={} ip={} username={}", 
                requestId, clientIp, request.getUsername());

            return ResponseEntity.ok(new RegistrationResponse(true, 
                "Please check your email to verify your account."));
        } catch (Exception e) {
            logger.error("Registration error request_id={}", requestId, e);
            return ResponseEntity.status(500)
                .body(new RegistrationResponse(false, "Registration failed. Please try again."));
        }
    }

    private boolean isRateLimited(String clientIp) {
        String key = "reg_rate:" + clientIp;
        Long count = redisTemplate.opsForValue().increment(key);
        if (count == 1) {
            redisTemplate.expire(key, Duration.ofMinutes(rateLimitWindowMinutes));
        }
        return count > rateLimitPerIp;
    }

    private CaptchaVerificationResult verifyCaptchaWithScoring(
            String token, String clientIp, double deviceScore) {
        // Adaptive threshold based on device trust score
        double requiredScore = deviceScore > 0.7 ? 0.3 : 0.7;

        RecaptchaResponse response = restTemplate.postForObject(
            "https://www.google.com/recaptcha/api/siteverify?secret=" + 
            recaptchaSecretKey + "&response=" + token + "&remoteip=" + clientIp,
            null, RecaptchaResponse.class);

        if (response == null || !response.isSuccess()) {
            return new CaptchaVerificationResult(false, 0.0);
        }

        return new CaptchaVerificationResult(
            response.getScore() >= requiredScore, 
            response.getScore());
    }

    private boolean isValidEmailDomain(String email) {
        String domain = extractDomain(email);
        // Check against disposable email domains
        return !DisposableEmailChecker.isDisposable(domain) &&
               DnsValidator.hasMxRecord(domain);
    }

    private boolean isReasonableSubmitTime(Long formLoadTimestamp) {
        if (formLoadTimestamp == null) return false;
        long elapsedMs = System.currentTimeMillis() - formLoadTimestamp;
        // Form submitted in less than 3 seconds or more than 1 hour is suspicious
        return elapsedMs >= 3000 && elapsedMs <= 3600000;
    }

    private String extractDomain(String email) {
        return email.substring(email.indexOf('@') + 1).toLowerCase();
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String createPendingRegistration(UserRegistration request, String clientIp) 
            throws SQLException {
        String verificationToken = generateSecureToken();
        // Store pending registration with 24-hour expiry
        // Account only activated after email verification
        return verificationToken;
    }

    private String generateSecureToken() {
        byte[] bytes = new byte[32];
        new java.security.SecureRandom().nextBytes(bytes);
        return java.util.Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }
}
```

**Defense in Depth Layers**:

1. **Rate Limiting by IP** (stops bulk attacks):
```java
// Redis-based sliding window rate limit
private boolean isRateLimited(String clientIp) {
    String key = "reg_rate:" + clientIp;
    Long count = redisTemplate.opsForValue().increment(key);
    if (count == 1) {
        redisTemplate.expire(key, Duration.ofMinutes(60));
    }
    return count > 5;  // Max 5 registrations per IP per hour
}
```

2. **Device Fingerprinting** (identifies automation):
```java
// Client-side collects: canvas hash, WebGL info, fonts, screen resolution
// Server-side analyzes for bot signatures
DeviceFingerprintResult fingerprint = fingerprintService.analyze(
    request.getDeviceFingerprint(),  // Hash of client characteristics
    clientIp,
    userAgent
);
// Known automation tools have distinct fingerprints
```

3. **Adaptive CAPTCHA Scoring** (increases friction for suspicious users):
```java
// Trusted devices get lower threshold, suspicious devices higher
double requiredScore = deviceScore > 0.7 ? 0.3 : 0.7;
```

**Additional Protections**:

- **Email verification**: Account only activated after clicking verification link - prevents using fake emails
- **Honeypot fields**: Hidden form field that bots fill but humans don't - catches naive bots
- **Timing analysis**: Forms submitted in <3 seconds indicate automation
- **Disposable email blocking**: Block tempmail.com, guerrillamail.com, etc.
- **MX record validation**: Verify email domain can actually receive mail
- **Progressive delays**: Slow down responses for suspicious patterns
- **Metrics and alerting**: Monitor registration patterns for anomaly detection

**Monitoring Dashboard Metrics**:
```java
// Set up alerts when these spike
registration.attempts.rate > baseline * 3  // Possible attack
registration.blocked.rate > 50%            // High bot activity  
registration.success.rate < 10%            // Legitimate users blocked?
```

This multi-layer approach makes attacks economically unviable - attackers must defeat rate limits, fingerprinting, CAPTCHA, email verification, and timing checks simultaneously.

Password change functionality is one of the most critical security operations in any application. A common mistake is allowing password changes without verifying the current password, which enables attackers who gain temporary session access (via XSS, session hijacking, or physical access) to permanently take over accounts.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"net/http"

	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type PasswordChangeRequest struct {
	UserID      int    `json:"user_id"`
	NewPassword string `json:"new_password"`
}

var db *sql.DB

// VULNERABLE: No current password verification, no session validation
func changePassword(w http.ResponseWriter, r *http.Request) {
	var req PasswordChangeRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// DANGEROUS: Directly accepts user_id from request body
	// No verification that requester owns this account
	hashedPassword, _ := bcrypt.GenerateFromPassword([]byte(req.NewPassword), bcrypt.DefaultCost)

	// VULNERABLE: No current password check, allows IDOR attack
	_, err := db.Exec("UPDATE users SET password = $1 WHERE id = $2",
		string(hashedPassword), req.UserID)

	if err != nil {
		http.Error(w, "Failed to update password", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"message": "Password updated"})
}
```

**Attack Payload**:
```bash
# Attacker changes any user's password without knowing current password
curl -X POST http://api.example.com/api/change-password \
  -H "Content-Type: application/json" \
  -H "Cookie: session=stolen_session_token" \
  -d '{"user_id": 12345, "new_password": "attacker_password123"}'

# IDOR attack - change another user's password
curl -X POST http://api.example.com/api/change-password \
  -H "Content-Type: application/json" \
  -H "Cookie: session=valid_attacker_session" \
  -d '{"user_id": 1, "new_password": "pwned_admin"}'
```

**Why This Is Dangerous**:
- No current password verification allows attackers with stolen sessions to lock out legitimate users permanently
- User ID from request body enables IDOR (Insecure Direct Object Reference) attacks - changing any user's password
- No password complexity validation allows weak passwords
- No rate limiting enables brute force session hijacking followed by instant password change
- Sessions remain valid after password change, allowing continued access

**SECURE VERSION**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"log"
	"net/http"
	"regexp"
	"time"
	"unicode"

	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type SecurePasswordChangeRequest struct {
	CurrentPassword string `json:"current_password"`
	NewPassword     string `json:"new_password"`
	ConfirmPassword string `json:"confirm_password"`
}

type User struct {
	ID           int
	Email        string
	PasswordHash string
}

var dbConn *sql.DB

func secureChangePassword(w http.ResponseWriter, r *http.Request) {
	// SECURITY: Get user ID from authenticated session, never from request
	userID, ok := r.Context().Value("userID").(int)
	if !ok {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	var req SecurePasswordChangeRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request format", http.StatusBadRequest)
		return
	}

	// SECURITY: Verify new password matches confirmation
	if req.NewPassword != req.ConfirmPassword {
		http.Error(w, "Passwords do not match", http.StatusBadRequest)
		return
	}

	// SECURITY: Validate password complexity
	if err := validatePasswordStrength(req.NewPassword); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// SECURITY: Fetch current password hash from database
	var currentHash string
	err := dbConn.QueryRow("SELECT password FROM users WHERE id = $1", userID).Scan(&currentHash)
	if err != nil {
		log.Printf("Password change failed - user lookup error for ID %d: %v", userID, err)
		http.Error(w, "Password change failed", http.StatusInternalServerError)
		return
	}

	// CRITICAL: Verify current password before allowing change
	if err := bcrypt.CompareHashAndPassword([]byte(currentHash), []byte(req.CurrentPassword)); err != nil {
		log.Printf("Password change failed - incorrect current password for user %d", userID)
		// Use constant-time response to prevent timing attacks
		time.Sleep(100 * time.Millisecond)
		http.Error(w, "Current password is incorrect", http.StatusUnauthorized)
		return
	}

	// SECURITY: Hash new password with appropriate cost
	newHash, err := bcrypt.GenerateFromPassword([]byte(req.NewPassword), 12)
	if err != nil {
		log.Printf("Password hashing failed for user %d: %v", userID, err)
		http.Error(w, "Password change failed", http.StatusInternalServerError)
		return
	}

	// Update password in transaction
	_, err = dbConn.Exec("UPDATE users SET password = $1, password_changed_at = $2 WHERE id = $3",
		string(newHash), time.Now().UTC(), userID)
	if err != nil {
		log.Printf("Password update failed for user %d: %v", userID, err)
		http.Error(w, "Password change failed", http.StatusInternalServerError)
		return
	}

	// SECURITY: Invalidate all other sessions after password change
	invalidateOtherSessions(userID, r)

	log.Printf("Password changed successfully for user %d from IP %s", userID, r.RemoteAddr)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"message": "Password changed successfully. Please log in again on other devices.",
	})
}

func validatePasswordStrength(password string) error {
	if len(password) < 12 {
		return fmt.Errorf("password must be at least 12 characters")
	}
	var hasUpper, hasLower, hasDigit, hasSpecial bool
	for _, c := range password {
		switch {
		case unicode.IsUpper(c):
			hasUpper = true
		case unicode.IsLower(c):
			hasLower = true
		case unicode.IsDigit(c):
			hasDigit = true
		case unicode.IsPunct(c) || unicode.IsSymbol(c):
			hasSpecial = true
		}
	}
	if !hasUpper || !hasLower || !hasDigit || !hasSpecial {
		return fmt.Errorf("password must contain uppercase, lowercase, digit, and special character")
	}
	return nil
}

func invalidateOtherSessions(userID int, currentRequest *http.Request) {
	// Implementation to invalidate all sessions except current
	currentSessionID := getSessionID(currentRequest)
	dbConn.Exec("DELETE FROM sessions WHERE user_id = $1 AND session_id != $2", userID, currentSessionID)
}
```

**Key Security Controls**:
- **Current password verification**: Attackers with stolen sessions cannot change passwords without knowing the current password
- **User ID from session context**: Prevents IDOR attacks by never trusting client-provided user identifiers
- **Password complexity validation**: Enforces strong passwords that resist brute force attacks
- **Session invalidation**: All other sessions are terminated after password change, limiting damage from compromised sessions
- **Audit logging**: All password change attempts are logged with IP addresses for forensic analysis

Password reset is even more critical than password change because it's designed to work when the user doesn't know their current password. This makes it a prime target for account takeover attacks. The key is implementing secure token generation, proper expiration, and preventing enumeration attacks.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"database/sql"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"

	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
	_ "github.com/lib/pq"
)

const (
	ResetTokenLength     = 32
	ResetTokenExpiration = 15 * time.Minute
	MaxResetAttempts     = 3
	ResetAttemptWindow   = 1 * time.Hour
)

type PasswordResetRequest struct {
	Email string `json:"email"`
}

type PasswordResetConfirm struct {
	Token           string `json:"token"`
	NewPassword     string `json:"new_password"`
	ConfirmPassword string `json:"confirm_password"`
}

type PasswordResetToken struct {
	ID        int
	UserID    int
	TokenHash string
	ExpiresAt time.Time
	Used      bool
	CreatedAt time.Time
	IPAddress string
}

var (
	db          *sql.DB
	rateLimiter = make(map[string]*rate.Limiter)
	rateMu      sync.RWMutex
)

// SECURE: Rate-limited password reset request
func requestPasswordReset(w http.ResponseWriter, r *http.Request) {
	clientIP := getClientIP(r)

	// SECURITY: Rate limit by IP to prevent enumeration
	if !checkRateLimit(clientIP, 5, time.Minute) {
		log.Printf("Rate limit exceeded for password reset from IP: %s", clientIP)
		// Return success to prevent enumeration
		respondWithGenericSuccess(w)
		return
	}

	var req PasswordResetRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		respondWithGenericSuccess(w) // Don't reveal validation errors
		return
	}

	// SECURITY: Validate email format
	if !isValidEmail(req.Email) {
		respondWithGenericSuccess(w)
		return
	}

	// Process reset asynchronously to ensure constant-time response
	go processPasswordResetRequest(req.Email, clientIP)

	// SECURITY: Always return same response regardless of email existence
	respondWithGenericSuccess(w)
}

func processPasswordResetRequest(email, clientIP string) {
	// Check if user exists
	var userID int
	var userEmail string
	err := db.QueryRow("SELECT id, email FROM users WHERE LOWER(email) = LOWER($1) AND active = true",
		email).Scan(&userID, &userEmail)

	if err != nil {
		// User doesn't exist - log but don't reveal
		log.Printf("Password reset requested for non-existent email: %s from IP: %s", maskEmail(email), clientIP)
		return
	}

	// SECURITY: Check rate limit per user
	var recentAttempts int
	db.QueryRow(`SELECT COUNT(*) FROM password_reset_tokens 
		WHERE user_id = $1 AND created_at > $2`,
		userID, time.Now().Add(-ResetAttemptWindow)).Scan(&recentAttempts)

	if recentAttempts >= MaxResetAttempts {
		log.Printf("Too many reset attempts for user %d from IP: %s", userID, clientIP)
		// Optionally notify user of suspicious activity
		sendSecurityAlert(userID, "Multiple password reset attempts detected")
		return
	}

	// SECURITY: Invalidate any existing reset tokens
	db.Exec("UPDATE password_reset_tokens SET used = true WHERE user_id = $1 AND used = false", userID)

	// SECURITY: Generate cryptographically secure token
	token, tokenHash, err := generateSecureResetToken()
	if err != nil {
		log.Printf("Failed to generate reset token for user %d: %v", userID, err)
		return
	}

	// Store hashed token (never store plaintext)
	expiresAt := time.Now().Add(ResetTokenExpiration)
	_, err = db.Exec(`INSERT INTO password_reset_tokens 
		(user_id, token_hash, expires_at, ip_address, created_at) 
		VALUES ($1, $2, $3, $4, $5)`,
		userID, tokenHash, expiresAt, clientIP, time.Now())

	if err != nil {
		log.Printf("Failed to store reset token for user %d: %v", userID, err)
		return
	}

	// Send reset email with token
	resetURL := fmt.Sprintf("https://example.com/reset-password?token=%s", token)
	sendPasswordResetEmail(userEmail, resetURL, clientIP)

	log.Printf("Password reset token generated for user %d, expires at %v", userID, expiresAt)
}

func generateSecureResetToken() (plainToken, hashedToken string, err error) {
	// Generate 32 bytes of cryptographically secure random data
	tokenBytes := make([]byte, ResetTokenLength)
	if _, err := rand.Read(tokenBytes); err != nil {
		return "", "", fmt.Errorf("failed to generate random bytes: %w", err)
	}

	// Encode as URL-safe base64 for the link
	plainToken = base64.URLEncoding.EncodeToString(tokenBytes)

	// Store SHA-256 hash of token (never store plaintext)
	hash := sha256.Sum256([]byte(plainToken))
	hashedToken = hex.EncodeToString(hash[:])

	return plainToken, hashedToken, nil
}

// SECURE: Password reset confirmation with token
func confirmPasswordReset(w http.ResponseWriter, r *http.Request) {
	clientIP := getClientIP(r)

	// SECURITY: Rate limit reset confirmations
	if !checkRateLimit(clientIP, 10, time.Minute) {
		log.Printf("Rate limit exceeded for reset confirmation from IP: %s", clientIP)
		http.Error(w, "Too many attempts. Please try again later.", http.StatusTooManyRequests)
		return
	}

	var req PasswordResetConfirm
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Validate passwords match
	if req.NewPassword != req.ConfirmPassword {
		http.Error(w, "Passwords do not match", http.StatusBadRequest)
		return
	}

	// Validate password strength
	if err := validatePasswordStrength(req.NewPassword); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// Hash the provided token to compare with stored hash
	tokenHash := sha256.Sum256([]byte(req.Token))
	tokenHashString := hex.EncodeToString(tokenHash[:])

	// Begin transaction for atomic operations
	tx, err := db.BeginTx(r.Context(), nil)
	if err != nil {
		log.Printf("Failed to begin transaction: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}
	defer tx.Rollback()

	// SECURITY: Find valid, unused, non-expired token
	var tokenRecord PasswordResetToken
	err = tx.QueryRow(`SELECT id, user_id, expires_at, used FROM password_reset_tokens 
		WHERE token_hash = $1`, tokenHashString).Scan(
		&tokenRecord.ID, &tokenRecord.UserID, &tokenRecord.ExpiresAt, &tokenRecord.Used)

	if err == sql.ErrNoRows {
		log.Printf("Invalid reset token attempted from IP: %s", clientIP)
		http.Error(w, "Invalid or expired reset link", http.StatusBadRequest)
		return
	}
	if err != nil {
		log.Printf("Database error during token lookup: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// SECURITY: Check if token is already used
	if tokenRecord.Used {
		log.Printf("Attempted reuse of reset token for user %d from IP: %s", tokenRecord.UserID, clientIP)
		http.Error(w, "This reset link has already been used", http.StatusBadRequest)
		return
	}

	// SECURITY: Check if token is expired
	if time.Now().After(tokenRecord.ExpiresAt) {
		log.Printf("Expired reset token for user %d from IP: %s", tokenRecord.UserID, clientIP)
		http.Error(w, "Reset link has expired. Please request a new one.", http.StatusBadRequest)
		return
	}

	// SECURITY: Mark token as used immediately (before password update)
	_, err = tx.Exec("UPDATE password_reset_tokens SET used = true, used_at = $1, used_ip = $2 WHERE id = $3",
		time.Now(), clientIP, tokenRecord.ID)
	if err != nil {
		log.Printf("Failed to mark token as used: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// Hash new password
	newPasswordHash, err := bcrypt.GenerateFromPassword([]byte(req.NewPassword), 12)
	if err != nil {
		log.Printf("Failed to hash password: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// Update password
	_, err = tx.Exec(`UPDATE users SET password = $1, password_changed_at = $2, 
		force_password_change = false WHERE id = $3`,
		string(newPasswordHash), time.Now(), tokenRecord.UserID)
	if err != nil {
		log.Printf("Failed to update password for user %d: %v", tokenRecord.UserID, err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// SECURITY: Invalidate all existing sessions
	_, err = tx.Exec("DELETE FROM sessions WHERE user_id = $1", tokenRecord.UserID)
	if err != nil {
		log.Printf("Failed to invalidate sessions for user %d: %v", tokenRecord.UserID, err)
	}

	// Commit transaction
	if err = tx.Commit(); err != nil {
		log.Printf("Failed to commit transaction: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// SECURITY: Send notification email about password change
	go sendPasswordChangedNotification(tokenRecord.UserID, clientIP)

	log.Printf("Password successfully reset for user %d from IP: %s", tokenRecord.UserID, clientIP)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"message": "Password reset successful. Please log in with your new password.",
	})
}

func checkRateLimit(key string, limit int, window time.Duration) bool {
	rateMu.Lock()
	defer rateMu.Unlock()

	limiter, exists := rateLimiter[key]
	if !exists {
		limiter = rate.NewLimiter(rate.Every(window/time.Duration(limit)), limit)
		rateLimiter[key] = limiter
	}
	return limiter.Allow()
}

func respondWithGenericSuccess(w http.ResponseWriter) {
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"message": "If an account exists with this email, you will receive a password reset link.",
	})
}

func getClientIP(r *http.Request) string {
	// Check X-Forwarded-For header (behind proxy)
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		// Take first IP from comma-separated list
		if idx := strings.Index(xff, ","); idx != -1 {
			return strings.TrimSpace(xff[:idx])
		}
		return strings.TrimSpace(xff)
	}
	// Fall back to RemoteAddr
	if idx := strings.LastIndex(r.RemoteAddr, ":"); idx != -1 {
		return r.RemoteAddr[:idx]
	}
	return r.RemoteAddr
}

func maskEmail(email string) string {
	parts := strings.Split(email, "@")
	if len(parts) != 2 {
		return "***"
	}
	if len(parts[0]) <= 2 {
		return "***@" + parts[1]
	}
	return parts[0][:2] + "***@" + parts[1]
}
```

**Defense in Depth Layers**:

1. **Token Security**:
```go
// Layer 1: Cryptographically secure random generation
tokenBytes := make([]byte, 32) // 256 bits of entropy
crypto_rand.Read(tokenBytes)

// Layer 2: Store only hashed tokens in database
hash := sha256.Sum256([]byte(plainToken))
// Attacker with DB access cannot use stolen token hashes
```

2. **Timing Attack Prevention**:
```go
// Layer 3: Constant-time responses prevent email enumeration
// Process request asynchronously, always return same message
go processPasswordResetRequest(email, clientIP)
respondWithGenericSuccess(w) // Same response for existing and non-existing emails
```

3. **Multi-Layer Rate Limiting**:
```go
// Layer 4: IP-based rate limiting
if !checkRateLimit(clientIP, 5, time.Minute) { ... }

// Layer 5: Per-user rate limiting
if recentAttempts >= MaxResetAttempts {
    sendSecurityAlert(userID, "Multiple password reset attempts")
}
```

**Additional Protections**:
- **Short token expiration** (15 minutes): Limits attack window for intercepted emails
- **Single-use tokens**: Tokens are marked used immediately before password update in same transaction
- **Session invalidation**: All sessions terminated after password reset to boot out attackers
- **Notification emails**: User is alerted when password is changed, enabling quick detection of unauthorized changes
- **Audit trail**: Complete logging of all reset attempts with IP addresses for forensic investigation
- **Atomic transactions**: Password update and token invalidation happen atomically to prevent race conditions
- **Breached password check**: Consider integrating HaveIBeenPwned API to reject known compromised passwords

Your registration form is likely vulnerable to automated bot attacks without CAPTCHA protection. This is a critical security gap that enables mass account creation attacks.

**VULNERABLE CODE**:

```php
<?php
require_once 'config.php';

class RegistrationController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function register() {
        if ($_SERVER['REQUEST_METHOD'] !== 'POST') {
            return ['error' => 'Invalid method'];
        }

        $username = trim($_POST['username'] ?? '');
        $email = trim($_POST['email'] ?? '');
        $password = $_POST['password'] ?? '';

        // Basic validation only
        if (empty($username) || empty($email) || empty($password)) {
            return ['error' => 'All fields are required'];
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return ['error' => 'Invalid email format'];
        }

        // No CAPTCHA verification - vulnerable to bots!
        $hashedPassword = password_hash($password, PASSWORD_DEFAULT);

        $stmt = $this->pdo->prepare(
            "INSERT INTO users (username, email, password, created_at) VALUES (?, ?, ?, NOW())"
        );

        try {
            $stmt->execute([$username, $email, $hashedPassword]);
            return ['success' => true, 'message' => 'Registration successful'];
        } catch (PDOException $e) {
            return ['error' => 'Registration failed'];
        }
    }
}
?>
```

**Attack Script** (Python bot example):
