            return false;
        }

        $response = file_get_contents(
            'https://www.google.com/recaptcha/api/siteverify?' . http_build_query([
                'secret' => $this->recaptchaSecret,
                'response' => $captchaResponse,
                'remoteip' => $_SERVER['REMOTE_ADDR']
            ])
        );

        $result = json_decode($response, true);
        return isset($result['success']) && $result['success'] === true;
    }

    private function validateCsrfToken($token) {
        return isset($_SESSION['csrf_token']) && hash_equals($_SESSION['csrf_token'], $token);
    }

    private function validateInput($username, $email, $password) {
        $errors = [];

        if (!preg_match('/^[a-zA-Z0-9_]{3,20}$/', $username)) {
            $errors[] = 'Username must be 3-20 alphanumeric characters';
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            $errors[] = 'Invalid email format';
        }

        if (strlen($password) < 12 || !preg_match('/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/', $password)) {
            $errors[] = 'Password must be 12+ chars with uppercase, lowercase, and number';
        }

        return $errors;
    }

    private function userExists($username, $email) {
        $stmt = $this->pdo->prepare("SELECT id FROM users WHERE username = ? OR email = ?");
        $stmt->execute([$username, $email]);
        return $stmt->fetch() !== false;
    }

    private function logSecurityEvent($event, $ip, $username = null) {
        $stmt = $this->pdo->prepare(
            "INSERT INTO security_logs (event_type, ip_address, username, created_at) VALUES (?, ?, ?, NOW())"
