<?php
require_once 'vendor/autoload.php';

class ProductionRegistrationController {
    private $pdo;
    private $redis;
    private $config;

    public function __construct($pdo, $redis) {
        $this->pdo = $pdo;
        $this->redis = $redis;
        $this->config = [
            'recaptcha_secret' => getenv('RECAPTCHA_V3_SECRET'),
            'recaptcha_threshold' => 0.5, // reCAPTCHA v3 score threshold
            'rate_limit_window' => 3600, // 1 hour
            'rate_limit_ip' => 5, // 5 registrations per IP per hour
            'rate_limit_email_domain' => 20, // per email domain
            'honeypot_field' => 'website_url', // bot trap field
            'min_form_time' => 3, // minimum seconds to fill form
        ];
    }

    public function register() {
        $startTime = microtime(true);
        $clientIp = $this->getClientIp();
        $requestId = bin2hex(random_bytes(16));

        // Layer 1: Rate limiting by IP
        if (!$this->checkIpRateLimit($clientIp)) {
            $this->logBotAttempt('rate_limit_ip', $clientIp, $requestId);
            $this->incrementThreatScore($clientIp, 10);
            return $this->jsonResponse(['error' => 'Too many registration attempts'], 429);
        }

        // Layer 2: Honeypot field check
        if (!empty($_POST[$this->config['honeypot_field']])) {
            $this->logBotAttempt('honeypot_triggered', $clientIp, $requestId);
            $this->incrementThreatScore($clientIp, 50);
            // Return success to confuse bots
            return $this->jsonResponse(['success' => true]);
        }

        // Layer 3: Form timing analysis
        $formStartTime = $_POST['_form_token_time'] ?? 0;
        $formDuration = time() - intval($formStartTime);
        if ($formDuration < $this->config['min_form_time']) {
            $this->logBotAttempt('form_too_fast', $clientIp, $requestId, [
                'duration' => $formDuration
            ]);
            $this->incrementThreatScore($clientIp, 30);
            return $this->jsonResponse(['error' => 'Please try again'], 400);
        }

        // Layer 4: reCAPTCHA v3 with score analysis
        $captchaResult = $this->verifyRecaptchaV3($_POST['g-recaptcha-response'] ?? '');
        if (!$captchaResult['success'] || $captchaResult['score'] < $this->config['recaptcha_threshold']) {
            $this->logBotAttempt('captcha_low_score', $clientIp, $requestId, [
                'score' => $captchaResult['score'] ?? 0
            ]);

            // Low scores trigger additional verification
            if (($captchaResult['score'] ?? 0) < 0.3) {
                $this->incrementThreatScore($clientIp, 40);
                return $this->jsonResponse([
                    'error' => 'Additional verification required',
                    'action' => 'email_verification'
                ], 403);
            }
        }

        // Layer 5: Browser fingerprint validation
        $fingerprint = $_POST['_fp'] ?? '';
        if (!$this->validateFingerprint($fingerprint, $clientIp)) {
            $this->logBotAttempt('invalid_fingerprint', $clientIp, $requestId);
            $this->incrementThreatScore($clientIp, 25);
        }

        // Layer 6: Email domain rate limiting and reputation
        $email = trim($_POST['email'] ?? '');
        $emailDomain = substr(strrchr($email, '@'), 1);

        if ($this->isDisposableEmail($emailDomain)) {
            $this->logBotAttempt('disposable_email', $clientIp, $requestId, [
                'domain' => $emailDomain
            ]);
            return $this->jsonResponse(['error' => 'Please use a permanent email address'], 400);
        }

        if (!$this->checkEmailDomainRateLimit($emailDomain)) {
            $this->logBotAttempt('email_domain_rate_limit', $clientIp, $requestId);
            return $this->jsonResponse(['error' => 'Too many registrations from this email provider'], 429);
        }

        // Layer 7: Check cumulative threat score
        $threatScore = $this->getThreatScore($clientIp);
        if ($threatScore > 100) {
            $this->logBotAttempt('high_threat_score', $clientIp, $requestId, [
                'score' => $threatScore
            ]);
            $this->blockIp($clientIp, 3600); // Block for 1 hour
            return $this->jsonResponse(['error' => 'Registration temporarily unavailable'], 403);
        }

        // All checks passed - proceed with registration
        return $this->processRegistration($requestId, $clientIp, $captchaResult['score'] ?? 0);
    }

    private function verifyRecaptchaV3($token) {
        if (empty($token)) {
            return ['success' => false, 'score' => 0];
        }

        $ch = curl_init();
        curl_setopt_array($ch, [
            CURLOPT_URL => 'https://www.google.com/recaptcha/api/siteverify',
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => http_build_query([
                'secret' => $this->config['recaptcha_secret'],
                'response' => $token,
                'remoteip' => $this->getClientIp()
            ]),
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_TIMEOUT => 5
        ]);

        $response = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($httpCode !== 200) {
            return ['success' => false, 'score' => 0];
        }

        return json_decode($response, true) ?? ['success' => false, 'score' => 0];
    }

    private function checkIpRateLimit($ip) {
        $key = "reg_limit:ip:{$ip}";
        $count = $this->redis->incr($key);

        if ($count === 1) {
            $this->redis->expire($key, $this->config['rate_limit_window']);
        }

        return $count <= $this->config['rate_limit_ip'];
    }

    private function checkEmailDomainRateLimit($domain) {
        $key = "reg_limit:domain:" . md5($domain);
        $count = $this->redis->incr($key);

        if ($count === 1) {
            $this->redis->expire($key, $this->config['rate_limit_window']);
        }

        return $count <= $this->config['rate_limit_email_domain'];
    }

    private function isDisposableEmail($domain) {
        // Check against known disposable email domains
        $disposableDomains = $this->redis->smembers('disposable_email_domains');
        if (in_array(strtolower($domain), $disposableDomains)) {
            return true;
        }

        // Check MX records exist
        return !checkdnsrr($domain, 'MX');
    }

    private function validateFingerprint($fingerprint, $ip) {
        if (empty($fingerprint) || strlen($fingerprint) < 20) {
            return false;
        }

        // Check if this fingerprint has been used with too many IPs
        $key = "fp_ips:" . md5($fingerprint);
        $this->redis->sadd($key, $ip);
        $this->redis->expire($key, 86400); // 24 hours

        $ipCount = $this->redis->scard($key);
        return $ipCount <= 3; // Same fingerprint from max 3 IPs
    }

    private function incrementThreatScore($ip, $points) {
        $key = "threat_score:{$ip}";
        $this->redis->incrby($key, $points);
        $this->redis->expire($key, 3600); // Decay after 1 hour
    }

    private function getThreatScore($ip) {
        return intval($this->redis->get("threat_score:{$ip}") ?? 0);
    }

    private function blockIp($ip, $duration) {
        $this->redis->setex("blocked_ip:{$ip}", $duration, 1);

        // Log to database for analysis
        $stmt = $this->pdo->prepare(
            "INSERT INTO blocked_ips (ip_address, reason, blocked_until) VALUES (?, 'threat_score', DATE_ADD(NOW(), INTERVAL ? SECOND))"
        );
        $stmt->execute([$ip, $duration]);
    }

    private function logBotAttempt($type, $ip, $requestId, $metadata = []) {
        $logData = [
            'timestamp' => date('c'),
            'request_id' => $requestId,
            'type' => $type,
            'ip' => $ip,
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? '',
            'metadata' => $metadata
        ];

