            "INSERT INTO bot_detection_logs (request_id, event_type, ip_address, user_agent, metadata, created_at) VALUES (?, ?, ?, ?, ?, NOW())"
        );
        $stmt->execute([
            $requestId,
            $type,
            $ip,
            $logData['user_agent'],
            json_encode($metadata)
        ]);

        // Send to SIEM/monitoring
