    }

    private function processRegistration($requestId, $ip, $captchaScore) {
        $username = trim($_POST['username'] ?? '');
        $email = trim($_POST['email'] ?? '');
        $password = $_POST['password'] ?? '';

        // Input validation
        if (!preg_match('/^[a-zA-Z0-9_]{3,20}$/', $username)) {
            return $this->jsonResponse(['error' => 'Invalid username format'], 400);
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return $this->jsonResponse(['error' => 'Invalid email format'], 400);
        }

        if (strlen($password) < 12) {
            return $this->jsonResponse(['error' => 'Password too short'], 400);
        }

        // Create user with pending email verification
        $verificationToken = bin2hex(random_bytes(32));
        $hashedPassword = password_hash($password, PASSWORD_ARGON2ID, [
            'memory_cost' => 65536,
            'time_cost' => 4,
            'threads' => 3
        ]);

        $this->pdo->beginTransaction();

        try {
            $stmt = $this->pdo->prepare(
                "INSERT INTO users (username, email, password, email_verified, verification_token, registration_ip, captcha_score, created_at) 
                 VALUES (?, ?, ?, 0, ?, ?, ?, NOW())"
            );
            $stmt->execute([$username, $email, $hashedPassword, $verificationToken, $ip, $captchaScore]);

            $userId = $this->pdo->lastInsertId();

            // Log successful registration
            $stmt = $this->pdo->prepare(
                "INSERT INTO registration_audit (user_id, request_id, ip_address, captcha_score, created_at) VALUES (?, ?, ?, ?, NOW())"
            );
            $stmt->execute([$userId, $requestId, $ip, $captchaScore]);

            $this->pdo->commit();

            // Send verification email asynchronously
            $this->queueVerificationEmail($email, $verificationToken);

            return $this->jsonResponse([
                'success' => true,
                'message' => 'Please check your email to verify your account'
            ]);

        } catch (PDOException $e) {
            $this->pdo->rollBack();

            if (strpos($e->getMessage(), 'Duplicate') !== false) {
                return $this->jsonResponse(['error' => 'Username or email already exists'], 409);
            }

            error_log("Registration error [{$requestId}]: " . $e->getMessage());
            return $this->jsonResponse(['error' => 'Registration failed'], 500);
        }
    }

    private function queueVerificationEmail($email, $token) {
        $this->redis->rpush('email_queue', json_encode([
            'type' => 'verification',
            'to' => $email,
            'token' => $token,
            'queued_at' => time()
        ]));
    }

    private function getClientIp() {
        // Handle proxies/load balancers
        $headers = ['HTTP_CF_CONNECTING_IP', 'HTTP_X_FORWARDED_FOR', 'REMOTE_ADDR'];
        foreach ($headers as $header) {
            if (!empty($_SERVER[$header])) {
                $ip = explode(',', $_SERVER[$header])[0];
                if (filter_var(trim($ip), FILTER_VALIDATE_IP)) {
                    return trim($ip);
                }
            }
        }
        return '0.0.0.0';
    }

    private function jsonResponse($data, $code = 200) {
        http_response_code($code);
        header('Content-Type: application/json');
        return json_encode($data);
    }
}
