    if (this.isSuspiciousUserAgent(userAgent)) {
      score += 20;
    }

    // Signal 6: Email domain reputation
    const emailDomain = req.body.email?.split('@')[1];
    if (await this.isDisposableEmail(emailDomain)) {
      score += 35;
    }

    return Math.min(score, 100);
  }

  async checkIpReputation(ip) {
    // Check against threat intelligence feeds
    const knownBad = await this.redis.sismember('bad_ips', ip);
    if (knownBad) return 50;

    // Check recent registration velocity from this IP
    const recentCount = await this.redis.get(`ip:${ip}:reg_count`);
    if (parseInt(recentCount || '0') > 5) return 30;

    return 0;
  }

  isSuspiciousUserAgent(ua) {
    const suspiciousPatterns = [
      /python-requests/i,
      /curl/i,
      /wget/i,
      /scrapy/i,
      /headless/i,
      /phantom/i,
      /selenium/i
    ];
    return suspiciousPatterns.some(p => p.test(ua));
  }

  async isDisposableEmail(domain) {
    const disposableDomains = await this.redis.smembers('disposable_email_domains');
    return disposableDomains.includes(domain);
  }
}

const botDetector = new BotDetector(redis);

