    challengeId,
    powNonce,
    timing // Client-side timing data
  } = req.body;

  // Validate all required fields
  if (!email || !password || !username || !captchaToken || !challengeId || !powNonce) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  try {
    // Layer 1: Verify Proof of Work
    const powData = await redis.get(`pow:${challengeId}`);
    if (!powData) {
      logSecurityEvent('POW_EXPIRED', req);
      return res.status(400).json({ error: 'Challenge expired, request new one' });
    }

    const { challenge, difficulty } = JSON.parse(powData);
    if (!verifyPoW(challenge, powNonce, difficulty)) {
      logSecurityEvent('POW_FAILED', req);
      return res.status(403).json({ error: 'Invalid proof of work' });
    }

    // Invalidate used challenge
    await redis.del(`pow:${challengeId}`);

    // Layer 2: Verify reCAPTCHA
    const captchaResult = await verifyRecaptchaEnterprise(captchaToken, req.ip, 'register');
    if (!captchaResult.valid || captchaResult.score < 0.5) {
      logSecurityEvent('CAPTCHA_FAILED', req, { score: captchaResult.score });
      return res.status(403).json({ error: 'CAPTCHA verification failed' });
    }

    // Layer 3: Behavioral risk scoring
    const riskScore = await botDetector.calculateRiskScore(req, timing || {});

    if (riskScore > 70) {
      logSecurityEvent('HIGH_RISK_REGISTRATION_BLOCKED', req, { riskScore });
      return res.status(403).json({ error: 'Registration blocked for security reasons' });
    }

    if (riskScore > 40) {
      // Additional verification required
      logSecurityEvent('ELEVATED_RISK_REGISTRATION', req, { riskScore });
      // Could trigger SMS verification or manual review
    }

    // Layer 4: Input validation
    if (!isValidEmail(email) || !isStrongPassword(password)) {
      return res.status(400).json({ error: 'Invalid email or weak password' });
    }

    // Create user with pending verification
    const hashedPassword = await bcrypt.hash(password, 12);
    const verificationToken = generateVerificationToken();
    const fingerprint = req.headers['x-device-fingerprint'] || 'unknown';

    const client = await pool.connect();
    try {
