      const result = await client.query(
        `INSERT INTO users 
         (email, password, username, email_verified, verification_token, 
          created_ip, device_fingerprint, risk_score, request_id) 
         VALUES ($1, $2, $3, false, $4, $5, $6, $7, $8) 
         RETURNING id`,
        [email, hashedPassword, username, verificationToken, 
         req.ip, fingerprint, riskScore, req.requestId]
      );

      // Track registration for rate limiting
      await redis.incr(`ip:${req.ip}:reg_count`);
      await redis.expire(`ip:${req.ip}:reg_count`, 86400);
      await redis.incr(`fp:${fingerprint}:count`);
      await redis.expire(`fp:${fingerprint}:count`, 86400);

      await client.query('COMMIT');

      // Send verification email asynchronously
      await sendVerificationEmail(email, verificationToken);

      logSecurityEvent('REGISTRATION_SUCCESS', req, { 
        userId: result.rows[0].id, 
        riskScore,
        captchaScore: captchaResult.score 
      });

      res.status(201).json({ 
        message: 'Account created. Please verify your email.',
        userId: result.rows[0].id 
      });

    } catch (dbError) {
      await client.query('ROLLBACK');
      throw dbError;
    } finally {
      client.release();
    }

  } catch (error) {
    if (error.code === '23505') {
      return res.status(409).json({ error: 'Account already exists' });
    }
    logSecurityEvent('REGISTRATION_ERROR', req, { error: error.message });
    res.status(500).json({ error: 'Registration failed' });
  }
