**SECURE VERSION**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"regexp"
	"time"

	"github.com/dpapathanasiou/go-recaptcha"
	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
	_ "github.com/lib/pq"
)

type SecureRegisterRequest struct {
	Username       string `json:"username"`
	Email          string `json:"email"`
	Password       string `json:"password"`
	RecaptchaToken string `json:"recaptcha_token"`
	Honeypot       string `json:"website"` // Hidden field - bots fill this
}

var (
	db           *sql.DB
	rateLimiters = make(map[string]*rate.Limiter)
)

func init() {
	recaptcha.Init(os.Getenv("RECAPTCHA_SECRET_KEY"))
}

func secureRegisterHandler(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 10*time.Second)
	defer cancel()

	clientIP := getClientIP(r)

	// DEFENSE 1: Rate limiting per IP
	limiter := getRateLimiter(clientIP)
	if !limiter.Allow() {
		log.Printf("SECURITY: Rate limit exceeded for IP %s on registration", clientIP)
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	var req SecureRegisterRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// DEFENSE 2: Honeypot field detection
	if req.Honeypot != "" {
		log.Printf("SECURITY: Bot detected via honeypot from IP %s", clientIP)
		// Return success to confuse bots, but don't create account
		w.WriteHeader(http.StatusCreated)
		json.NewEncoder(w).Encode(map[string]string{"message": "Account created"})
		return
	}

	// DEFENSE 3: reCAPTCHA verification
	if req.RecaptchaToken == "" {
		http.Error(w, "CAPTCHA verification required", http.StatusBadRequest)
		return
	}

	verified, err := recaptcha.Confirm(clientIP, req.RecaptchaToken)
	if err != nil || !verified {
		log.Printf("SECURITY: CAPTCHA verification failed for IP %s", clientIP)
		http.Error(w, "CAPTCHA verification failed", http.StatusForbidden)
		return
	}

	// DEFENSE 4: Input validation
	if !validateRegistrationInput(req) {
		http.Error(w, "Invalid input", http.StatusBadRequest)
		return
	}

	// Create account with email verification pending
	verificationToken := generateSecureToken(32)
	hashedPassword, err := bcrypt.GenerateFromPassword([]byte(req.Password), bcrypt.DefaultCost)
	if err != nil {
		log.Printf("ERROR: Password hashing failed: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	_, err = db.ExecContext(ctx,
		`INSERT INTO users (username, email, password_hash, email_verified, verification_token, created_at) 
		 VALUES ($1, $2, $3, false, $4, NOW())`,
		req.Username, req.Email, hashedPassword, verificationToken,
	)
	if err != nil {
		log.Printf("ERROR: User creation failed: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	// DEFENSE 5: Email verification required
	go sendVerificationEmail(req.Email, verificationToken)

	log.Printf("INFO: New registration from IP %s, username: %s", clientIP, req.Username)
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(map[string]string{
		"message": "Account created. Please verify your email.",
	})
}

func getRateLimiter(ip string) *rate.Limiter {
	if limiter, exists := rateLimiters[ip]; exists {
		return limiter
	}
	limiter := rate.NewLimiter(rate.Every(time.Minute), 3) // 3 registrations per minute
	rateLimiters[ip] = limiter
	return limiter
}
```

**Key Security Controls**:
- **reCAPTCHA verification**: Proves human interaction, blocks automated scripts
- **Honeypot field**: Hidden form field that bots auto-fill, humans leave empty
- **Rate limiting**: Prevents rapid-fire registration attempts from same IP
- **Email verification**: Accounts remain inactive until email is confirmed
- **Security logging**: All suspicious activity logged for monitoring

Sophisticated attackers use CAPTCHA-solving services and headless browsers to bypass basic protections. Production systems need behavioral analysis, device fingerprinting, and risk-based authentication.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
