type ProductionRegisterRequest struct {
	Username        string `json:"username"`
	Email           string `json:"email"`
	Password        string `json:"password"`
	RecaptchaToken  string `json:"recaptcha_token"`
	Honeypot        string `json:"website"`
	DeviceFingerprint string `json:"device_fingerprint"`
	TimingToken     string `json:"timing_token"`
}

type RiskAssessment struct {
	Score       int
	Factors     []string
	Action      string
	RequireMFA  bool
}

type RegistrationService struct {
	db           *sql.DB
	redisClient  *redis.Client
	rateLimiters sync.Map
	recaptchaKey string
	ipReputationAPI string
}

func NewRegistrationService(db *sql.DB, redisClient *redis.Client) *RegistrationService {
	return &RegistrationService{
		db:              db,
		redisClient:     redisClient,
		recaptchaKey:    os.Getenv("RECAPTCHA_SECRET_KEY"),
		ipReputationAPI: os.Getenv("IP_REPUTATION_API"),
	}
}

func (s *RegistrationService) HandleRegistration(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 15*time.Second)
	defer cancel()

	clientIP := s.getClientIP(r)
	userAgent := r.Header.Get("User-Agent")
	requestID := s.generateRequestID()

	log.Printf("[%s] Registration attempt from IP: %s, UA: %s", requestID, clientIP, userAgent)

	// LAYER 1: Global rate limiting
	if s.isGloballyRateLimited(ctx) {
		log.Printf("[%s] SECURITY: Global rate limit active", requestID)
		http.Error(w, "Service temporarily unavailable", http.StatusServiceUnavailable)
		return
	}

	// LAYER 2: IP-based rate limiting with Redis
	if blocked, reason := s.checkIPRateLimit(ctx, clientIP); blocked {
		log.Printf("[%s] SECURITY: IP rate limited - %s", requestID, reason)
		s.recordSecurityEvent(ctx, "rate_limit_exceeded", clientIP, nil)
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	// LAYER 3: IP reputation check
	ripRisk := s.checkIPReputation(ctx, clientIP)
	if ipRisk.Score > 80 {
		log.Printf("[%s] SECURITY: High-risk IP blocked - score: %d", requestID, ipRisk.Score)
		s.recordSecurityEvent(ctx, "high_risk_ip_blocked", clientIP, ipRisk.Factors)
		http.Error(w, "Registration not available", http.StatusForbidden)
		return
	}

	var req ProductionRegisterRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// LAYER 4: Honeypot detection
	if req.Honeypot != "" {
		log.Printf("[%s] SECURITY: Bot detected via honeypot", requestID)
		s.recordSecurityEvent(ctx, "honeypot_triggered", clientIP, nil)
		// Fake success response
		s.fakeSuccessResponse(w)
		return
	}

	// LAYER 5: Timing analysis (detect instant form submissions)
	if !s.validateTimingToken(ctx, req.TimingToken) {
		log.Printf("[%s] SECURITY: Suspicious timing detected", requestID)
		s.recordSecurityEvent(ctx, "timing_anomaly", clientIP, nil)
		http.Error(w, "Please try again", http.StatusBadRequest)
		return
	}

	// LAYER 6: Device fingerprint analysis
	deviceRisk := s.analyzeDeviceFingerprint(ctx, req.DeviceFingerprint, clientIP)
	if deviceRisk.Score > 70 {
		log.Printf("[%s] SECURITY: Suspicious device fingerprint - score: %d", requestID, deviceRisk.Score)
		s.recordSecurityEvent(ctx, "suspicious_device", clientIP, deviceRisk.Factors)
		if deviceRisk.Score > 90 {
			http.Error(w, "Registration not available", http.StatusForbidden)
			return
		}
	}

	// LAYER 7: reCAPTCHA v3 with score analysis
	captchaResult := s.verifyRecaptchaV3(ctx, req.RecaptchaToken, clientIP)
	if !captchaResult.Success || captchaResult.Score < 0.5 {
		log.Printf("[%s] SECURITY: CAPTCHA failed - score: %.2f", requestID, captchaResult.Score)
		s.recordSecurityEvent(ctx, "captcha_failed", clientIP, []string{fmt.Sprintf("score:%.2f", captchaResult.Score)})
		http.Error(w, "Verification failed. Please try again.", http.StatusForbidden)
		return
	}

	// LAYER 8: Input validation and sanitization
	if validationErr := s.validateAndSanitizeInput(&req); validationErr != nil {
		log.Printf("[%s] Validation failed: %v", requestID, validationErr)
		http.Error(w, validationErr.Error(), http.StatusBadRequest)
		return
	}

	// LAYER 9: Email domain reputation
	emailDomain := strings.Split(req.Email, "@")[1]
	if s.isDisposableEmailDomain(emailDomain) {
		log.Printf("[%s] SECURITY: Disposable email domain rejected: %s", requestID, emailDomain)
		http.Error(w, "Please use a permanent email address", http.StatusBadRequest)
		return
	}

	// LAYER 10: Check for duplicate accounts with fuzzy matching
	if exists, similarity := s.checkSimilarAccounts(ctx, req.Username, req.Email); exists {
		log.Printf("[%s] Similar account detected - similarity: %.2f", requestID, similarity)
		if similarity > 0.9 {
			http.Error(w, "Account may already exist", http.StatusConflict)
			return
		}
	}

	// Calculate overall risk score
	riskAssessment := s.calculateRiskScore(ipRisk, deviceRisk, captchaResult.Score)

	// Create account with appropriate verification level
	verificationToken := s.generateSecureToken(32)
	hashedPassword, err := bcrypt.GenerateFromPassword([]byte(req.Password), 12)
	if err != nil {
		log.Printf("[%s] ERROR: Password hashing failed", requestID)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	tx, err := s.db.BeginTx(ctx, nil)
	if err != nil {
		log.Printf("[%s] ERROR: Transaction failed", requestID)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}
	defer tx.Rollback()

	var userID int64
	err = tx.QueryRowContext(ctx,
		`INSERT INTO users (username, email, password_hash, email_verified, verification_token, 
			risk_score, requires_mfa, registration_ip, user_agent, created_at) 
		 VALUES ($1, $2, $3, false, $4, $5, $6, $7, $8, NOW())
		 RETURNING id`,
		req.Username, req.Email, hashedPassword, verificationToken,
		riskAssessment.Score, riskAssessment.RequireMFA, clientIP, userAgent,
	).Scan(&userID)

	if err != nil {
		log.Printf("[%s] ERROR: User creation failed: %v", requestID, err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	// Store device fingerprint for future correlation
	_, err = tx.ExecContext(ctx,
		`INSERT INTO user_devices (user_id, fingerprint, first_seen, last_seen, ip_address)
		 VALUES ($1, $2, NOW(), NOW(), $3)`,
		userID, req.DeviceFingerprint, clientIP,
	)
	if err != nil {
		log.Printf("[%s] WARNING: Device tracking failed: %v", requestID, err)
	}

	if err = tx.Commit(); err != nil {
		log.Printf("[%s] ERROR: Transaction commit failed", requestID)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	// Send verification email asynchronously
	go s.sendVerificationEmail(req.Email, verificationToken, riskAssessment)

	// Record successful registration
	s.recordSecurityEvent(ctx, "registration_success", clientIP, []string{
		fmt.Sprintf("username:%s", req.Username),
		fmt.Sprintf("risk_score:%d", riskAssessment.Score),
	})

	log.Printf("[%s] SUCCESS: User registered - ID: %d, Risk: %d", requestID, userID, riskAssessment.Score)

	response := map[string]interface{}{
		"message":    "Account created. Please check your email for verification.",
		"user_id":    userID,
		"mfa_required": riskAssessment.RequireMFA,
	}
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(response)
}

func (s *RegistrationService) checkIPRateLimit(ctx context.Context, ip string) (bool, string) {
	key := fmt.Sprintf("reg_rate:%s", ip)

	// Check registration attempts in last hour
	count, err := s.redisClient.Incr(ctx, key).Result()
	if err != nil {
		log.Printf("WARNING: Redis rate limit check failed: %v", err)
		return false, ""
	}

	if count == 1 {
		s.redisClient.Expire(ctx, key, time.Hour)
	}

	if count > 5 {
		return true, fmt.Sprintf("exceeded %d attempts in hour", count)
	}

	return false, ""
}

func (s *RegistrationService) validateTimingToken(ctx context.Context, token string) bool {
	if token == "" {
		return false
	}

	key := fmt.Sprintf("timing_token:%s", token)
	val, err := s.redisClient.Get(ctx, key).Result()
	if err != nil {
		return false
	}

	// Token should be at least 3 seconds old (human typing time)
	var createdAt time.Time
	if err := createdAt.UnmarshalText([]byte(val)); err != nil {
		return false
	}

	elapsed := time.Since(createdAt)
	return elapsed >= 3*time.Second && elapsed <= 30*time.Minute
}

func (s *RegistrationService) generateSecureToken(length int) string {
	bytes := make([]byte, length)
	if _, err := rand.Read(bytes); err != nil {
		log.Printf("ERROR: Secure token generation failed: %v", err)
		return ""
	}
	return base64.URLEncoding.EncodeToString(bytes)
}

func (s *RegistrationService) recordSecurityEvent(ctx context.Context, eventType, ip string, details []string) {
	_, err := s.db.ExecContext(ctx,
		`INSERT INTO security_events (event_type, ip_address, details, created_at)
		 VALUES ($1, $2, $3, NOW())`,
		eventType, ip, strings.Join(details, ","),
	)
	if err != nil {
		log.Printf("WARNING: Security event logging failed: %v", err)
	}
}
