```go
// Sliding window rate limiting with Redis
func (s *RegistrationService) advancedRateLimit(ctx context.Context, ip string) bool {
	now := time.Now().Unix()
	windowKey := fmt.Sprintf("reg_window:%s", ip)

	pipe := s.redisClient.Pipeline()
	pipe.ZRemRangeByScore(ctx, windowKey, "0", fmt.Sprintf("%d", now-3600))
	pipe.ZAdd(ctx, windowKey, redis.Z{Score: float64(now), Member: now})
	pipe.ZCard(ctx, windowKey)
	pipe.Expire(ctx, windowKey, time.Hour)

	results, _ := pipe.Exec(ctx)
	count := results[2].(*redis.IntCmd).Val()

	return count > 5
}
