func (s *RegistrationService) analyzeDeviceFingerprint(ctx context.Context, fp, ip string) RiskAssessment {
	risk := RiskAssessment{Score: 0, Factors: []string{}}

	// Check how many accounts use this fingerprint
	var count int
	s.db.QueryRowContext(ctx,
		"SELECT COUNT(DISTINCT user_id) FROM user_devices WHERE fingerprint = $1",
		fp).Scan(&count)

	if count > 3 {
		risk.Score += 40
		risk.Factors = append(risk.Factors, "multiple_accounts_same_device")
	}

	// Check for known malicious fingerprints
	var isMalicious bool
	s.db.QueryRowContext(ctx,
		"SELECT EXISTS(SELECT 1 FROM malicious_fingerprints WHERE fingerprint = $1)",
		fp).Scan(&isMalicious)

