Password change functionality is a critical security feature that attackers frequently target. A poorly implemented password change can lead to complete account takeover without requiring the attacker to know the original password.

**VULNERABLE CODE**:

```php
<?php
session_start();
require_once 'database.php';

class PasswordController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function changePassword() {
        // VULNERABLE: No current password verification
        // VULNERABLE: User ID from client-side input
        $userId = $_POST['user_id'];
        $newPassword = $_POST['new_password'];

        // VULNERABLE: No password complexity validation
        // VULNERABLE: MD5 is cryptographically broken
        $hashedPassword = md5($newPassword);

        // VULNERABLE: Direct query without session validation
        $sql = "UPDATE users SET password = '$hashedPassword' WHERE id = $userId";
        $this->pdo->exec($sql);

        echo json_encode(['success' => true, 'message' => 'Password changed']);
    }
}

$controller = new PasswordController($pdo);
$controller->changePassword();
?>
```

**Attack Payload**:
```http
POST /change_password.php HTTP/1.1
Host: vulnerable-site.com
Content-Type: application/x-www-form-urlencoded
Cookie: PHPSESSID=attacker_session

user_id=12345&new_password=hacked123
```

**Why This Is Dangerous**:
- No verification of current password allows attackers with session access to change passwords
- User ID from POST data enables Insecure Direct Object Reference (IDOR) attacks
- No session validation means any authenticated user can change any password
- MD5 hashing is cryptographically broken and vulnerable to rainbow table attacks
- SQL injection vulnerability in the UPDATE query
- No password complexity requirements allows weak passwords
- No CSRF protection enables cross-site attacks

**SECURE VERSION**:

```php
<?php
session_start();
require_once 'database.php';
require_once 'csrf_token.php';

class SecurePasswordController {
    private $pdo;
    private const MIN_PASSWORD_LENGTH = 12;
    private const PASSWORD_PATTERN = '/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/'; 

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function changePassword(): array {
        // SECURE: Verify CSRF token
        if (!$this->verifyCsrfToken($_POST['csrf_token'] ?? '')) {
            return ['success' => false, 'error' => 'Invalid request token'];
        }

        // SECURE: Get user ID from authenticated session only
        if (!isset($_SESSION['user_id']) || !isset($_SESSION['authenticated'])) {
            return ['success' => false, 'error' => 'Not authenticated'];
        }
        $userId = $_SESSION['user_id'];

        $currentPassword = $_POST['current_password'] ?? '';
        $newPassword = $_POST['new_password'] ?? '';
        $confirmPassword = $_POST['confirm_password'] ?? '';

        // SECURE: Verify current password first
        if (!$this->verifyCurrentPassword($userId, $currentPassword)) {
            $this->logSecurityEvent('password_change_failed', $userId, 'Invalid current password');
            sleep(1); // Rate limiting delay
            return ['success' => false, 'error' => 'Current password is incorrect'];
        }

        // SECURE: Validate new password matches confirmation
        if ($newPassword !== $confirmPassword) {
            return ['success' => false, 'error' => 'New passwords do not match'];
        }

        // SECURE: Validate password complexity
        $validationResult = $this->validatePasswordStrength($newPassword);
        if (!$validationResult['valid']) {
            return ['success' => false, 'error' => $validationResult['message']];
        }

        // SECURE: Ensure new password differs from current
        if (password_verify($newPassword, $this->getCurrentHash($userId))) {
            return ['success' => false, 'error' => 'New password must differ from current'];
        }

        // SECURE: Use bcrypt with cost factor
        $hashedPassword = password_hash($newPassword, PASSWORD_BCRYPT, ['cost' => 12]);

        // SECURE: Parameterized query prevents SQL injection
        $stmt = $this->pdo->prepare(
            "UPDATE users SET password = :password, password_changed_at = NOW(), 
             must_change_password = 0 WHERE id = :user_id"
        );
        $stmt->execute([':password' => $hashedPassword, ':user_id' => $userId]);

        // SECURE: Invalidate all other sessions
        $this->invalidateOtherSessions($userId);

        // SECURE: Log successful password change
        $this->logSecurityEvent('password_changed', $userId, 'Password changed successfully');

        return ['success' => true, 'message' => 'Password changed successfully'];
    }

    private function verifyCurrentPassword(int $userId, string $password): bool {
        $stmt = $this->pdo->prepare("SELECT password FROM users WHERE id = :id");
        $stmt->execute([':id' => $userId]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        return $user && password_verify($password, $user['password']);
    }

    private function validatePasswordStrength(string $password): array {
        if (strlen($password) < self::MIN_PASSWORD_LENGTH) {
            return ['valid' => false, 'message' => 'Password must be at least 12 characters'];
        }
        if (!preg_match(self::PASSWORD_PATTERN, $password)) {
            return ['valid' => false, 'message' => 'Password must include uppercase, lowercase, number, and special character'];
        }
        // Check against common passwords
        if ($this->isCommonPassword($password)) {
            return ['valid' => false, 'message' => 'Password is too common'];
        }
        return ['valid' => true, 'message' => ''];
    }

    private function isCommonPassword(string $password): bool {
        $commonPasswords = file('common_passwords.txt', FILE_IGNORE_NEW_LINES);
        return in_array(strtolower($password), $commonPasswords);
    }

    private function getCurrentHash(int $userId): string {
        $stmt = $this->pdo->prepare("SELECT password FROM users WHERE id = :id");
        $stmt->execute([':id' => $userId]);
        return $stmt->fetchColumn() ?: '';
    }

    private function invalidateOtherSessions(int $userId): void {
        $currentSessionId = session_id();
        $stmt = $this->pdo->prepare(
            "DELETE FROM user_sessions WHERE user_id = :user_id AND session_id != :current"
        );
        $stmt->execute([':user_id' => $userId, ':current' => $currentSessionId]);
    }

    private function verifyCsrfToken(string $token): bool {
        return isset($_SESSION['csrf_token']) && 
               hash_equals($_SESSION['csrf_token'], $token);
    }

    private function logSecurityEvent(string $event, int $userId, string $details): void {
        $stmt = $this->pdo->prepare(
            "INSERT INTO security_logs (event_type, user_id, details, ip_address, user_agent, created_at) 
             VALUES (:event, :user_id, :details, :ip, :ua, NOW())"
        );
        $stmt->execute([
            ':event' => $event,
            ':user_id' => $userId,
            ':details' => $details,
            ':ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            ':ua' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown'
        ]);
    }
}
?>
```

**Key Security Controls**:
- **Current password verification**: Ensures the person making the change knows the existing password, preventing account takeover from stolen sessions
- **Session-based user ID**: User ID comes from the server-side session, not client input, preventing IDOR attacks
- **Password complexity validation**: Enforces strong passwords with minimum length, character variety, and common password checking
- **Bcrypt hashing with cost factor**: Uses modern, secure password hashing resistant to brute-force attacks
- **CSRF protection**: Prevents cross-site request forgery attacks
- **Session invalidation**: Logs out all other sessions after password change, limiting damage from compromised sessions

Password reset functionality is even more security-critical than password change because it's designed to work when the user doesn't know their current password. This makes it a prime target for account takeover attacks.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

namespace App\Security;

use PDO;
use DateTimeImmutable;
use Exception;

class SecurePasswordResetService {
    private PDO $pdo;
    private EmailService $emailService;
    private RateLimiter $rateLimiter;
    private SecurityLogger $logger;

    private const TOKEN_EXPIRY_MINUTES = 15;
    private const TOKEN_LENGTH = 32;
    private const MAX_RESET_ATTEMPTS_PER_HOUR = 3;
    private const MAX_RESET_ATTEMPTS_PER_IP = 10;

    public function __construct(
        PDO $pdo, 
        EmailService $emailService,
        RateLimiter $rateLimiter,
        SecurityLogger $logger
    ) {
        $this->pdo = $pdo;
        $this->emailService = $emailService;
        $this->rateLimiter = $rateLimiter;
        $this->logger = $logger;
    }

    /**
     * Request password reset - generates token and sends email
     */
    public function requestPasswordReset(string $email, string $ipAddress): array {
        // SECURE: Rate limiting per IP to prevent enumeration
        if (!$this->rateLimiter->checkLimit('reset_ip', $ipAddress, self::MAX_RESET_ATTEMPTS_PER_IP, 3600)) {
            $this->logger->logSecurityEvent('rate_limit_exceeded', [
                'type' => 'password_reset_ip',
                'ip' => $ipAddress
            ]);
            // SECURE: Return same message to prevent timing attacks
            return $this->getGenericSuccessResponse();
        }

        // SECURE: Validate email format
        $email = filter_var(trim($email), FILTER_VALIDATE_EMAIL);
        if (!$email) {
            return $this->getGenericSuccessResponse();
        }

        // SECURE: Rate limiting per email address
        if (!$this->rateLimiter->checkLimit('reset_email', $email, self::MAX_RESET_ATTEMPTS_PER_HOUR, 3600)) {
            $this->logger->logSecurityEvent('rate_limit_exceeded', [
                'type' => 'password_reset_email',
                'email' => $this->maskEmail($email)
            ]);
            return $this->getGenericSuccessResponse();
        }

        // Lookup user by email
        $user = $this->getUserByEmail($email);

        // SECURE: Always return same response regardless of email existence
        // This prevents user enumeration attacks
        if (!$user) {
            $this->logger->logSecurityEvent('password_reset_nonexistent_email', [
                'email' => $this->maskEmail($email),
                'ip' => $ipAddress
            ]);
            // Simulate same timing as successful request
            usleep(random_int(100000, 300000));
            return $this->getGenericSuccessResponse();
        }

        // SECURE: Check if account is locked or disabled
        if ($user['account_locked'] || !$user['email_verified']) {
            $this->logger->logSecurityEvent('password_reset_blocked_account', [
                'user_id' => $user['id'],
                'reason' => $user['account_locked'] ? 'locked' : 'unverified'
            ]);
            return $this->getGenericSuccessResponse();
        }

        // SECURE: Invalidate any existing tokens for this user
        $this->invalidateExistingTokens($user['id']);

        // SECURE: Generate cryptographically secure token
        $token = bin2hex(random_bytes(self::TOKEN_LENGTH));

        // SECURE: Store hashed token (not plaintext)
        $tokenHash = hash('sha256', $token);
        $expiresAt = (new DateTimeImmutable())
            ->modify('+' . self::TOKEN_EXPIRY_MINUTES . ' minutes')
            ->format('Y-m-d H:i:s');

        $this->storeResetToken($user['id'], $tokenHash, $expiresAt, $ipAddress);

        // SECURE: Send reset email with token
        $resetUrl = $this->generateResetUrl($token);
        $this->emailService->sendPasswordResetEmail(
            $email,
            $user['name'],
            $resetUrl,
            self::TOKEN_EXPIRY_MINUTES
        );

        $this->logger->logSecurityEvent('password_reset_requested', [
            'user_id' => $user['id'],
            'ip' => $ipAddress,
            'expires_at' => $expiresAt
        ]);

        return $this->getGenericSuccessResponse();
    }

    /**
     * Validate reset token and allow password change
     */
    public function validateResetToken(string $token): ?array {
        if (strlen($token) !== self::TOKEN_LENGTH * 2) {
            return null;
        }

        // SECURE: Hash the provided token before lookup
        $tokenHash = hash('sha256', $token);

        $stmt = $this->pdo->prepare("
            SELECT prt.*, u.email, u.name, u.account_locked
            FROM password_reset_tokens prt
            JOIN users u ON prt.user_id = u.id
            WHERE prt.token_hash = :token_hash
            AND prt.used_at IS NULL
            AND prt.expires_at > NOW()
            LIMIT 1
        ");
        $stmt->execute([':token_hash' => $tokenHash]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$result || $result['account_locked']) {
            return null;
        }

        return [
            'valid' => true,
            'user_id' => $result['user_id'],
            'email' => $result['email'],
            'token_id' => $result['id']
        ];
    }

    /**
     * Complete password reset with new password
     */
    public function completePasswordReset(
        string $token, 
        string $newPassword, 
        string $confirmPassword,
        string $ipAddress
    ): array {
        // Validate token first
        $tokenData = $this->validateResetToken($token);

        if (!$tokenData) {
            $this->logger->logSecurityEvent('password_reset_invalid_token', [
                'ip' => $ipAddress
            ]);
            return ['success' => false, 'error' => 'Invalid or expired reset link'];
        }

        // Validate password match
        if ($newPassword !== $confirmPassword) {
            return ['success' => false, 'error' => 'Passwords do not match'];
        }

        // Validate password strength
        $validation = $this->validatePasswordStrength($newPassword);
        if (!$validation['valid']) {
            return ['success' => false, 'error' => $validation['message']];
        }

        // Check password history (prevent reuse of last 5 passwords)
        if ($this->isPasswordInHistory($tokenData['user_id'], $newPassword)) {
            return ['success' => false, 'error' => 'Cannot reuse recent passwords'];
        }

        try {
            $this->pdo->beginTransaction();

            // SECURE: Hash password with bcrypt
            $hashedPassword = password_hash($newPassword, PASSWORD_BCRYPT, ['cost' => 12]);

            // Update password
            $stmt = $this->pdo->prepare("
                UPDATE users SET 
                    password = :password,
                    password_changed_at = NOW(),
                    failed_login_attempts = 0,
                    account_locked = 0
                WHERE id = :user_id
            ");
            $stmt->execute([
                ':password' => $hashedPassword,
                ':user_id' => $tokenData['user_id']
            ]);

            // Add to password history
            $this->addToPasswordHistory($tokenData['user_id'], $hashedPassword);

            // SECURE: Mark token as used (one-time use)
            $stmt = $this->pdo->prepare("
                UPDATE password_reset_tokens 
                SET used_at = NOW(), used_ip = :ip
                WHERE id = :token_id
            ");
            $stmt->execute([
                ':ip' => $ipAddress,
                ':token_id' => $tokenData['token_id']
            ]);

            // SECURE: Invalidate all existing sessions
            $this->invalidateAllSessions($tokenData['user_id']);

            $this->pdo->commit();

            // Send confirmation email
            $this->emailService->sendPasswordChangedNotification(
                $tokenData['email'],
                $ipAddress
            );

            $this->logger->logSecurityEvent('password_reset_completed', [
                'user_id' => $tokenData['user_id'],
                'ip' => $ipAddress
            ]);

            return ['success' => true, 'message' => 'Password has been reset successfully'];

        } catch (Exception $e) {
            $this->pdo->rollBack();
            $this->logger->logSecurityEvent('password_reset_error', [
                'user_id' => $tokenData['user_id'],
                'error' => $e->getMessage()
            ]);
            return ['success' => false, 'error' => 'An error occurred. Please try again.'];
        }
    }

    private function getUserByEmail(string $email): ?array {
        $stmt = $this->pdo->prepare("
            SELECT id, email, name, account_locked, email_verified 
            FROM users WHERE LOWER(email) = LOWER(:email) LIMIT 1
        ");
        $stmt->execute([':email' => $email]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    private function invalidateExistingTokens(int $userId): void {
        $stmt = $this->pdo->prepare("
            UPDATE password_reset_tokens 
            SET expires_at = NOW() 
            WHERE user_id = :user_id AND used_at IS NULL
        ");
        $stmt->execute([':user_id' => $userId]);
    }

    private function storeResetToken(
        int $userId, 
        string $tokenHash, 
        string $expiresAt,
        string $ipAddress
    ): void {
        $stmt = $this->pdo->prepare("
            INSERT INTO password_reset_tokens 
            (user_id, token_hash, expires_at, created_ip, created_at)
            VALUES (:user_id, :token_hash, :expires_at, :ip, NOW())
        ");
        $stmt->execute([
            ':user_id' => $userId,
            ':token_hash' => $tokenHash,
            ':expires_at' => $expiresAt,
            ':ip' => $ipAddress
        ]);
    }

    private function generateResetUrl(string $token): string {
        $baseUrl = getenv('APP_URL') ?: 'https://example.com';
        return $baseUrl . '/reset-password?token=' . urlencode($token);
    }

    private function validatePasswordStrength(string $password): array {
        if (strlen($password) < 12) {
            return ['valid' => false, 'message' => 'Password must be at least 12 characters'];
        }
        if (!preg_match('/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/', $password)) {
            return ['valid' => false, 'message' => 'Password must include uppercase, lowercase, number, and special character'];
        }
        return ['valid' => true, 'message' => ''];
    }

    private function isPasswordInHistory(int $userId, string $password): bool {
        $stmt = $this->pdo->prepare("
            SELECT password_hash FROM password_history 
            WHERE user_id = :user_id 
            ORDER BY created_at DESC LIMIT 5
        ");
        $stmt->execute([':user_id' => $userId]);

        while ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {
            if (password_verify($password, $row['password_hash'])) {
                return true;
            }
        }
        return false;
    }

    private function addToPasswordHistory(int $userId, string $hashedPassword): void {
        $stmt = $this->pdo->prepare("
            INSERT INTO password_history (user_id, password_hash, created_at)
            VALUES (:user_id, :hash, NOW())
        ");
        $stmt->execute([':user_id' => $userId, ':hash' => $hashedPassword]);
    }

    private function invalidateAllSessions(int $userId): void {
        $stmt = $this->pdo->prepare("DELETE FROM user_sessions WHERE user_id = :user_id");
        $stmt->execute([':user_id' => $userId]);
    }

    private function getGenericSuccessResponse(): array {
        return [
            'success' => true, 
            'message' => 'If an account exists with this email, you will receive reset instructions'
        ];
    }

    private function maskEmail(string $email): string {
        $parts = explode('@', $email);
        $name = $parts[0];
        $domain = $parts[1] ?? '';
        $masked = substr($name, 0, 2) . '***' . '@' . $domain;
        return $masked;
    }
}
